package br.com.saqz.groups.data.finance

import br.com.saqz.network.*
import io.ktor.client.engine.mock.*
import io.ktor.client.request.HttpRequestData
import io.ktor.client.request.HttpResponseData
import io.ktor.http.*
import io.ktor.http.content.TextContent
import kotlinx.coroutines.test.runTest
import kotlinx.serialization.json.*
import kotlin.test.*

class FinanceApiTest {
    @Test fun `organizer charges preserve cents identity status audit and totals`()=runTest{val result=organizer{json(CHARGES)}.charges(GROUP);val value=assertIs<NetworkResult.Success<ChargeListDto>>(result).value;val game=value.charges.first();assertEquals(2500,game.amountCents);assertEquals(ChargeKindDto.GAME,game.kind);assertEquals(GAME,game.gameId);assertNull(game.month);assertEquals(ChargeStatusDto.PENDING,game.status);assertEquals(ChargeStatusDto.PAID,game.events.single().newStatus);assertEquals(2500,value.pendingTotalCents);assertEquals(5000,value.paidTotalCents)}
    @Test fun `monthly charge preserves month member and cancelled status`()=runTest{val value=assertIs<NetworkResult.Success<ChargeListDto>>(organizer{json(CHARGES)}.charges(GROUP)).value.charges.last();assertEquals(ChargeKindDto.MONTHLY,value.kind);assertEquals("2026-08",value.month);assertEquals(MEMBER,value.memberId);assertEquals(ChargeStatusDto.CANCELLED,value.status)}
    @Test fun `athlete gateway calls only own charge route and receives no group totals`()=runTest{val result=athlete{request->assertEquals(HttpMethod.Get,request.method);assertEquals("/api/groups/$GROUP/charges/me",request.url.encodedPath);json(OWN_CHARGES)}.ownCharges(GROUP);val value=assertIs<NetworkResult.Success<ChargeListDto>>(result).value;assertEquals(MEMBER,value.charges.single().memberId);assertNull(value.pendingTotalCents);assertNull(value.paidTotalCents)}
    @Test fun `finance DTO contains no settlement partial refund balance or credential fields`()=runTest{organizer{request->val body=request.body as TextContent;val keys=Json.parseToJsonElement(body.text).jsonObject.keys;assertTrue(keys.none{it.lowercase() in setOf("settlement","partial","refund","balance","credential","token")});json(CHARGES)}.generateMonthly(GROUP,monthly())}
    @Test fun `monthly generation sends stable key month cents due date and members only`()=runTest{organizer{request->assertEquals(HttpMethod.Post,request.method);assertEquals("/api/groups/$GROUP/charges/monthly",request.url.encodedPath);val body=request.json();assertEquals(setOf("requestId","month","amountCents","dueDate","memberIds"),body.keys);assertEquals(KEY,body.getValue("requestId").jsonPrimitive.content);assertEquals(7000,body.getValue("amountCents").jsonPrimitive.long);assertEquals(setOf(MEMBER,MEMBER2),body.getValue("memberIds").jsonArray.map{it.jsonPrimitive.content}.toSet());json(OWN_CHARGES)}.generateMonthly(GROUP,monthly())}
    @Test fun `charge status sends quoted ETag exact status and optional note`()=runTest{organizer{request->assertEquals("/api/groups/$GROUP/charges/$CHARGE/status",request.url.encodedPath);assertEquals("\"4\"",request.headers[HttpHeaders.IfMatch]);val body=request.json();assertEquals(setOf("status","note"),body.keys);assertEquals("WAIVED",body.getValue("status").jsonPrimitive.content);versioned(CHARGE_JSON,"\"5\"")}.updateChargeStatus(GROUP,CHARGE,"\"4\"",ChargeStatusCommandDto(ChargeStatusDto.WAIVED,"Ajuste manual"))}
    @Test fun `charge status preserves returned ETag and appended audit`()=runTest{val result=organizer{versioned(CHARGE_JSON,"\"5\"")}.updateChargeStatus(GROUP,CHARGE,"\"4\"",ChargeStatusCommandDto(ChargeStatusDto.PAID));val value=assertIs<NetworkResult.Success<VersionedChargeDto>>(result).value;assertEquals("\"5\"",value.etag);assertEquals("actor-1",value.charge.events.single().actorId)}
    @Test fun `expense list preserves exact category custom notes events and active total`()=runTest{val result=organizer{json(EXPENSES)}.expenses(GROUP);val value=assertIs<NetworkResult.Success<ExpenseListDto>>(result).value;val expense=value.expenses.single();assertEquals(12345,expense.amountCents);assertEquals(ExpenseCategoryDto.OTHER,expense.category);assertEquals("Água",expense.customCategory);assertEquals(ExpenseStatusDto.ACTIVE,expense.status);assertEquals(ExpenseActionDto.CREATED,expense.events.single().action);assertEquals(12345,value.activeExpenseTotalCents)}
    @Test fun `expense create sends idempotency key and returns ETag`()=runTest{val result=organizer{request->assertEquals(HttpMethod.Post,request.method);assertEquals("/api/groups/$GROUP/expenses",request.url.encodedPath);assertEquals(KEY,request.json().getValue("requestId").jsonPrimitive.content);versioned(EXPENSE_JSON,"\"1\"")}.createExpense(GROUP,expense(KEY));assertEquals("\"1\"",assertIs<NetworkResult.Success<VersionedExpenseDto>>(result).value.etag)}
    @Test fun `expense edit sends exact integer cents vocabulary and ETag`()=runTest{organizer{request->assertEquals(HttpMethod.Put,request.method);assertEquals("/api/groups/$GROUP/expenses/$EXPENSE",request.url.encodedPath);assertEquals("\"1\"",request.headers[HttpHeaders.IfMatch]);val body=request.json();assertEquals(12345,body.getValue("amountCents").jsonPrimitive.long);assertEquals("OTHER",body.getValue("category").jsonPrimitive.content);versioned(EXPENSE_JSON,"\"2\"")}.editExpense(GROUP,EXPENSE,"\"1\"",expense())}
    @Test fun `expense void has no mutation body and preserves ETag`()=runTest{val result=organizer{request->assertEquals(HttpMethod.Post,request.method);assertEquals("/api/groups/$GROUP/expenses/$EXPENSE/void",request.url.encodedPath);assertEquals("\"2\"",request.headers[HttpHeaders.IfMatch]);versioned(VOID_EXPENSE_JSON,"\"3\"")}.voidExpense(GROUP,EXPENSE,"\"2\"");val value=assertIs<NetworkResult.Success<VersionedExpenseDto>>(result).value;assertEquals(ExpenseStatusDto.VOIDED,value.expense.status);assertEquals("\"3\"",value.etag)}
    @Test fun `finance totals preserve all charge buckets and active expenses`()=runTest{val result=organizer{request->assertEquals("/api/groups/$GROUP/finance/totals",request.url.encodedPath);json(TOTALS)}.totals(GROUP);assertEquals(FinanceTotalsDto(2500,5000,1000,7000,12345),assertIs<NetworkResult.Success<FinanceTotalsDto>>(result).value)}
    @Test fun `auth refresh retries identical monthly key and body`()=runTest{var calls=0;val bodies=mutableListOf<String>();val api=organizer(RefreshingTokens()){request->calls++;bodies+=(request.body as TextContent).text;if(calls==1)unauthorized() else json(OWN_CHARGES)};api.generateMonthly(GROUP,monthly());assertEquals(2,calls);assertEquals(bodies.first(),bodies.last());assertEquals(KEY,Json.parseToJsonElement(bodies.last()).jsonObject.getValue("requestId").jsonPrimitive.content)}
    @Test fun `auth refresh preserves expense edit body key and ETag`()=runTest{var calls=0;val bodies=mutableListOf<String>();val etags=mutableListOf<String?>();val api=organizer(RefreshingTokens()){request->calls++;bodies+=(request.body as TextContent).text;etags+=request.headers[HttpHeaders.IfMatch];if(calls==1)unauthorized() else versioned(EXPENSE_JSON,"\"2\"")};api.editExpense(GROUP,EXPENSE,"\"1\"",expense(KEY));assertEquals(bodies.first(),bodies.last());assertEquals(listOf<String?>("\"1\"","\"1\""),etags)}
    @Test fun `validation preserves exact finance field errors`() {val failure=problem(400,"VALIDATION_FAILED",mapOf("amountCents" to listOf("is invalid"))).toFinanceGatewayFailure();assertEquals(mapOf("amountCents" to listOf("is invalid")),assertIs<FinanceGatewayFailure.Validation>(failure).fields)}
    @Test fun `stale hidden and forbidden finance outcomes remain distinct`() {assertEquals(FinanceGatewayFailure.Conflict,problem(409,"VERSION_CONFLICT").toFinanceGatewayFailure());assertEquals(FinanceGatewayFailure.HiddenResource,problem(404,"GROUP_NOT_FOUND").toFinanceGatewayFailure());assertEquals(FinanceGatewayFailure.Forbidden,problem(403,"ACCESS_FORBIDDEN").toFinanceGatewayFailure())}
    @Test fun `precondition lifecycle authentication temporary and unknown remain distinct`() {assertEquals(FinanceGatewayFailure.PreconditionRequired,problem(428,"PRECONDITION_REQUIRED").toFinanceGatewayFailure());assertEquals(FinanceGatewayFailure.InvalidLifecycle,problem(409,"INVALID_GAME_TRANSITION").toFinanceGatewayFailure());assertEquals(FinanceGatewayFailure.Authentication,problem(401,"AUTHENTICATION_REQUIRED").toFinanceGatewayFailure());assertEquals(FinanceGatewayFailure.Temporary,NetworkError.Timeout.toFinanceGatewayFailure());assertEquals(FinanceGatewayFailure.InvalidResponse,problem(400,"UNKNOWN").toFinanceGatewayFailure())}
    @Test fun `versioned finance mutations reject missing ETags`()=runTest{val status=organizer{json(CHARGE_JSON)}.updateChargeStatus(GROUP,CHARGE,"\"4\"",ChargeStatusCommandDto(ChargeStatusDto.PAID));val create=organizer{json(EXPENSE_JSON)}.createExpense(GROUP,expense(KEY));assertEquals(NetworkError.InvalidResponse,assertIs<NetworkResult.Failure>(status).error);assertEquals(NetworkError.InvalidResponse,assertIs<NetworkResult.Failure>(create).error)}

    private fun monthly()=MonthlyChargeCommandDto(KEY,"2026-08",7000,"2026-08-10",linkedSetOf(MEMBER,MEMBER2))
    private fun expense(key:String?=null)=ExpenseWriteCommandDto(key,"Água do jogo",12345,"2026-08-12",ExpenseCategoryDto.OTHER,"Água","Compra manual")
    private fun athlete(handler:suspend MockRequestHandleScope.(HttpRequestData)->HttpResponseData)=AthleteFinanceApi(auth(Tokens(),handler))
    private fun organizer(tokens:IdTokenProvider=Tokens(),handler:suspend MockRequestHandleScope.(HttpRequestData)->HttpResponseData)=OrganizerFinanceApi(auth(tokens,handler))
    private fun auth(tokens:IdTokenProvider,handler:suspend MockRequestHandleScope.(HttpRequestData)->HttpResponseData):AuthenticatedNetworkClient{val network=NetworkClient(MockEngine{request->handler(request)},NetworkConfig(NetworkEnvironment.Test,"https://api.example.test/"));return AuthenticatedNetworkClient(network,tokens,NoopInvalidator())}
    private fun MockRequestHandleScope.json(body:String)=respond(body,headers=jsonHeaders())
    private fun MockRequestHandleScope.versioned(body:String,etag:String)=respond(body,headers=headersOf(HttpHeaders.ContentType to listOf("application/json"),HttpHeaders.ETag to listOf(etag)))
    private fun MockRequestHandleScope.unauthorized()=respond("""{"status":401,"code":"AUTHENTICATION_REQUIRED","correlationId":"c"}""",HttpStatusCode.Unauthorized,jsonHeaders())
    private fun HttpRequestData.json()=Json.parseToJsonElement((body as TextContent).text).jsonObject
    private fun jsonHeaders()=headersOf(HttpHeaders.ContentType,"application/json")
    private fun problem(status:Int,code:String,fields:Map<String,List<String>>?=null)=NetworkError.ApiProblemError(ApiProblem(status,code,"c",fields))
    private class Tokens:IdTokenProvider{override fun token(forceRefresh:Boolean,completion:(TokenResult)->Unit)=completion(TokenResult.Available("token"))}
    private class RefreshingTokens:IdTokenProvider{override fun token(forceRefresh:Boolean,completion:(TokenResult)->Unit)=completion(TokenResult.Available(if(forceRefresh)"fresh" else "old"))}
    private class NoopInvalidator:SessionInvalidator{override fun invalidate()=Unit}
    private companion object {
        const val GROUP="group-1";const val GAME="game-1";const val MEMBER="member-1";const val MEMBER2="member-2";const val CHARGE="charge-1";const val EXPENSE="expense-1";const val KEY="finance-key"
        const val CHARGE_JSON="""{"id":"charge-1","groupId":"group-1","memberId":"member-1","kind":"GAME","gameId":"game-1","month":null,"amountCents":2500,"dueDate":"2026-08-12","status":"PENDING","reviewRequired":true,"version":5,"events":[{"actorId":"actor-1","oldStatus":"PENDING","newStatus":"PAID","note":"Recebido","occurredAt":"2026-08-12T10:00:00Z"}]}"""
        const val CHARGES="""{"charges":[$CHARGE_JSON,{"id":"charge-2","groupId":"group-1","memberId":"member-1","kind":"MONTHLY","gameId":null,"month":"2026-08","amountCents":7000,"dueDate":"2026-08-10","status":"CANCELLED","version":2,"events":[]}],"pendingTotalCents":2500,"paidTotalCents":5000,"waivedTotalCents":1000,"cancelledTotalCents":7000}"""
        const val OWN_CHARGES="""{"charges":[$CHARGE_JSON]}"""
        const val EXPENSE_JSON="""{"id":"expense-1","groupId":"group-1","description":"Água do jogo","amountCents":12345,"expenseDate":"2026-08-12","category":"OTHER","customCategory":"Água","notes":"Compra manual","status":"ACTIVE","version":1,"events":[{"actorId":"actor-1","action":"CREATED","occurredAt":"2026-08-12T10:00:00Z"}]}"""
        const val VOID_EXPENSE_JSON="""{"id":"expense-1","groupId":"group-1","description":"Água do jogo","amountCents":12345,"expenseDate":"2026-08-12","category":"OTHER","customCategory":"Água","notes":"Compra manual","status":"VOIDED","version":3,"events":[{"actorId":"actor-1","action":"VOIDED","occurredAt":"2026-08-13T10:00:00Z"}]}"""
        const val EXPENSES="""{"expenses":[$EXPENSE_JSON],"activeExpenseTotalCents":12345}"""
        const val TOTALS="""{"pendingChargeCents":2500,"paidChargeCents":5000,"waivedChargeCents":1000,"cancelledChargeCents":7000,"activeExpenseCents":12345}"""
    }
}
